module RefModule(
  output reg [2:0] cycle,
  input clk,
  input enn
);reg [2:0] register = 3'b000;

  always @(posedge clk) begin
    if(!enn)
      register <= (register == 3'b111) ? 3'b000 : register + 1;
    else
      register <= 3'b000;
  end

  wire __cycle_tmp = register;
  assign cycle = __cycle_tmp;

endmodule
